Here is a simple C++ function that uses the `std::regex` library to replace Markdown syntax with HTML. This function only supports a limited set of Markdown syntax, including bold, italic, headers, and links.

```cpp
#include <regex>
#include <string>

std::string markdownToHtml(const std::string& markdown) {
    std::string html;
    std::regex boldRegex("^(\\*|__)([^\\*]+)\\1$");
    std::regex italicRegex("^(\\*|_)([^\\*]+)\\1$");
    std::regex headerRegex("^# (.*)$");
    std::regex linkRegex("\\[(.*)\\]\\(([^\\)]+)\\)");

    html += "<p>";
    for (size_t i = 0; i < markdown.size(); ++i) {
        if (markdown[i] == '#') {
            size_t j = i + 1;
            while (markdown[j] != '\n' && markdown[j] != '\0') {
                ++j;
            }
            html += "<h" + std::to_string(j - i - 1) + ">" + markdown.substr(i, j - i) + "</h" + std::to_string(j - i - 1) + ">";
            i = j;
        } else if (std::regex_match(markdown.substr(i), boldRegex, std::regex_constants::match_default)) {
            html += "<b>" + std::regex_replace(markdown.substr(i), boldRegex, "$2") + "</b>";
            i += std::regex_match(markdown.substr(i), boldRegex, std::regex_constants::match_default) - 1;
        } else if (std::regex_match(markdown.substr(i), italicRegex, std::regex_constants::match_default)) {
            html += "<i>" + std::regex_replace(markdown.substr(i), italicRegex, "$2") + "</i>";
            i += std::regex_match(markdown.substr(i), italicRegex, std::regex_constants::match_default) - 1;
        } else if (std::regex_match(markdown.substr(i), linkRegex, std::regex_constants::match_default)) {
            html += "<a href=\"" + std::regex_replace(markdown.substr(i), linkRegex, "$2") + "\">" + std::regex_replace(markdown.substr(i), linkRegex, "$1") + "</a>";
            i += std::regex_match(markdown.substr(i), linkRegex, std::regex_constants::match_default) - 1;
        } else {
            html += markdown[i];
        }
    }
    html += "</p>";
    return html;
}
```

This function assumes that the input Markdown text is well-formed and does not contain any invalid syntax. It also does not support nested Markdown syntax. You may need to add more code to handle these cases if you need to support more complex Markdown syntax.

Also, this function does not handle any HTML entities in the input Markdown text. If the input Markdown text contains HTML entities, you will need to add code to handle them.

You can use this function like this:

```cpp
int main() {
    std::string markdown = "Hello **world**. This is a _test_ link to [Google](https://www.google.com).";
    std::string html = markdownToHtml(markdown);
    std::cout << html << std::endl;
    return 0;
}
```

This will output:

```
<p><h1>Hello <b>world</b>. This is a <i>test</i> <a href="https://www.google.com">link to Google</a>.</p>
```

