Creating a smooth snake game in C that uses images to animate the whole level is a challenging task, but I'll provide a basic outline to get you started. We'll use the SDL (Simple DirectMedia Layer) library to handle graphics and input.

**Prerequisites:**

1. Install SDL development libraries (SDL2) on your system.
2. Familiarize yourself with C programming and basic game development concepts.

**Game Requirements:**

1. The game will have a 2D grid (e.g., 20x20 cells) where the snake will move.
2. The snake will be represented by an image (e.g., a PNG file).
3. The game will have a food item (e.g., an apple) that the snake can eat to grow.
4. The game will have a score that increases when the snake eats the food.
5. The game will have a boundary (e.g., the edge of the grid) that the snake cannot cross.

**Code Structure:**

We'll divide the code into several files:

1. `snake.h`: Header file with function prototypes and game constants.
2. `snake.c`: Main game logic and event handling.
3. `snake_graphics.c`: Image loading and rendering.
4. `snake_input.c`: Input handling (keyboard and mouse).

**snake.h:**
```c
#ifndef SNAKE_H
#define SNAKE_H

// Game constants
#define GRID_WIDTH 20
#define GRID_HEIGHT 20
#define SNAKE_SPEED 10 // frames per second
#define FOOD_SPAWN_RATE 100 // frames between food spawns

// Snake direction
enum direction { UP, DOWN, LEFT, RIGHT };

// Snake structure
typedef struct {
    int x, y; // position
    int length; // number of cells
    enum direction direction; // current direction
} Snake;

// Food structure
typedef struct {
    int x, y; // position
} Food;

// Game state
extern Snake snake;
extern Food food;
extern int score;
extern int game_over;

#endif // SNAKE_H
```
**snake.c:**
```c
#include "snake.h"
#include "snake_graphics.h"
#include "snake_input.h"

// Initialize game state
void init_game() {
    snake.length = 5; // initial snake length
    snake.direction = RIGHT;
    snake.x = GRID_WIDTH / 2;
    snake.y = GRID_HEIGHT / 2;

    food.x = (rand() % GRID_WIDTH);
    food.y = (rand() % GRID_HEIGHT);

    score = 0;
    game_over = 0;
}

// Update game state
void update_game() {
    // Move snake
    switch (snake.direction) {
        case UP:
            snake.y -= 1;
            break;
        case DOWN:
            snake.y += 1;
            break;
        case LEFT:
            snake.x -= 1;
            break;
        case RIGHT:
            snake.x += 1;
            break;
    }

    // Check for collisions
    if (snake.x < 0 || snake.x >= GRID_WIDTH || snake.y < 0 || snake.y >= GRID_HEIGHT) {
        game_over = 1;
    }

    // Check for food
    if (snake.x == food.x && snake.y == food.y) {
        snake.length++;
        score++;
        food.x = (rand() % GRID_WIDTH);
        food.y = (rand() % GRID_HEIGHT);
    }
}

// Render game state
void render_game() {
    // Clear screen
    SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
    SDL_RenderClear(renderer);

    // Draw snake
    for (int i = 0; i < snake.length; i++) {
        SDL_Rect rect = { snake.x * 20, snake.y * 20, 20, 20 };
        SDL_RenderFillRect(renderer, &rect);
    }

    // Draw food
    SDL_Rect food_rect = { food.x * 20, food.y * 20, 20, 20 };
    SDL_RenderFillRect(renderer, &food_rect);

    // Update screen
    SDL_RenderPresent(renderer);
}

// Main game loop
int main() {
    // Initialize SDL
    SDL_Init(SDL_INIT_VIDEO);

    // Create window and renderer
    window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, 400, 400, SDL_WINDOW_SHOWN);
    renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

    // Initialize game state
    init_game();

    // Main loop
    while (!game_over) {
        // Handle events
        SDL_Event event;
        while (SDL_PollEvent(&event)) {
            if (event.type == SDL_QUIT) {
                game_over = 1;
            } else if (event.type == SDL_KEYDOWN) {
                switch (event.key.keysym.sym) {
                    case SDLK_UP:
                        snake.direction = UP;
                        break;
                    case SDLK_DOWN:
                        snake.direction = DOWN;
                        break;
                    case SDLK_LEFT:
                        snake.direction = LEFT;
                        break;
                    case SDLK_RIGHT:
                        snake.direction = RIGHT;
                        break;
                }
            }
        }

        // Update game state
        update_game();

        // Render game state
        render_game();

        // Cap frame rate
        SDL_Delay(1000 / SNAKE_SPEED);
    }

    // Clean up
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();

    return 0;
}
```
